-- =====================================================================
-- Script de peuplement (seed) - Gestion de Cimetière GI2
-- PostgreSQL - données SYNTHÉTIQUES (patronymes/prénoms/villes congolais
-- réels et attestés, mais personnes fictives - voir explication du chat).
-- SÉCURITÉ : chaque compte a un mot de passe UNIQUE et aléatoire.
-- Les mots de passe en clair sont fournis UNIQUEMENT dans le fichier
-- credentials_initiaux.csv (à distribuer en main propre à chaque agent,
-- PUIS à supprimer/ne jamais committer). Forcez un changement de mot de
-- passe via l'endpoint /api/auth/password/change dès la première connexion.
-- Idempotent : peut être rejoué (TRUNCATE ... CASCADE en tête).
-- =====================================================================

-- Force l'encodage client, quel que soit celui du terminal/outil qui
-- exécute ce script (cause fréquente d'accents corrompus type 'reÃ§u'
-- sous Windows). Sans ceci, psql/pgAdmin peuvent relire ce fichier
-- UTF-8 avec un mauvais encodage et corrompre les caractères accentués
-- AVANT même que cette ligne s'exécute -- voir instructions dans le chat
-- pour la configuration côté client (PGCLIENTENCODING / chcp 65001).
SET client_encoding = 'UTF8';

BEGIN;

TRUNCATE TABLE
    audit_auditlog,
    notifications_notification,
    payments_momotransaction,
    payments_paiement,
    exhumations_exhumation,
    concessions_concession,
    reservations_reservation,
    cemetery_defunt,
    cemetery_grave,
    cemetery_bloc,
    cemetery_section,
    accounts_user
RESTART IDENTITY CASCADE;

